import type { Location } from './location-model';

export interface Doctor {
  /**
   * @displayName Doctor ID
   * @description Unique system identifier - GUID generated by system
   * @uiConstraints NEVER create input fields for this ID
   */
  id: string;
  /**
   * @displayName Name
   * @description Human-readable record identifier
   * @validationRule Required for create/update operations
   */
  name1: string;
  /**
   * @displayName Bio
   */
  bio?: string;
  /**
   * @displayName Consultation Fee
   */
  consultationFee?: number;
  /**
   * @displayName Experience Years
   * @validationRule Required for create/update operations
   */
  experienceYears: number;
  /**
   * @displayName Image URL
   */
  imageURL?: string;
  /**
   * @displayName Is Available
   * @validationRule Required for create/update operations
   */
  isAvailable: boolean;
  /**
   * @displayName Languages
   */
  languages?: string;
  /**
   * @displayName Location
   */
  location?: Pick<Location, 'id' | 'name1'>;
  /**
   * @displayName Next Available Slot
   */
  nextAvailableSlot?: string;
  /**
   * @displayName Qualifications
   */
  qualifications?: string;
  /**
   * @displayName Rating
   */
  rating?: number;
  /**
   * @displayName Registration Number
   */
  registrationNumber?: string;
  /**
   * @displayName Services Offered
   */
  servicesOffered?: string;
  /**
   * @displayName Specialty
   * @validationRule Required for create/update operations
   */
  specialty: string;
}

export const _Doctor = 'Doctor' as const;